class _HomePageState extends State<HomePage> {
  StreamSubscription? _sub;

  @override
  void initState() {
    super.initState();
    _initUniLinks();
  }

  Future<void> _initUniLinks() async {
    try {
      final initialLink = await getInitialLink();
      if (initialLink != null) {
        _handleDeepLink(initialLink);
      }
    } on FormatException catch (e) {
      debugPrint('Failed to parse the initial link: $e');
    }

    _sub = uriLinkStream.listen((Uri? uri) {
      if (!mounted) return;
      if (uri != null) {
        _handleDeepLink(uri.toString());
      }
    }, onError: (Object err) {
      if (!mounted) return;
      debugPrint('Error handling deep link: $err');
    });
  }

  void _handleDeepLink(String link) {
    try {
      final uri = Uri.parse(link);
      debugPrint('Deep Link received: $uri');

      final String host = uri.host;
      final List<String> pathSegments = uri.pathSegments;

      switch (host) {
        case 'profile':
          if (pathSegments.isNotEmpty) {
            final String userId = pathSegments.first;
            Navigator.of(context).push(
              MaterialPageRoute(
                builder: (context) => ProfilePage(userId: userId),
              ),
            );
          } else {
            debugPrint('Deep link to profile missing user ID: $link');
          }
          break;
        case 'payment':
          if (pathSegments.isNotEmpty && pathSegments.first == 'confirm') {
            Navigator.of(context).push(
              MaterialPageRoute(
                builder: (context) => const PaymentConfirmPage(),
              ),
            );
          } else {
            debugPrint('Deep link to payment unknown action: $link');
          }
          break;
        default:
          debugPrint('Unknown deep link host: $host for link: $link');
          break;
      }
    } on FormatException catch (e) {
      debugPrint('Invalid deep link format: $e');
    }
  }

